            {invoicePdf && <Button style={{background:"#dc2626",color:"#fff",border:"none"}} onClick={()=>invoicePdf(selectedTrip)}>📄 PDF</Button>}
            {printReceipt && <Button onClick={()=>printReceipt(selectedTrip)}>🧾 Makbuz</Button>}
