          <TripDetailPanel row={selectedTrip} updateTripStatus={updateTripStatus} updateTripAdvanced={updateTripAdvanced} canEdit={canEdit} />
        </>}
      </motion.div>
    </motion.div>}
  </AnimatePresence>
  </>;
