  const mapPoints = rows.slice(0,8).map((r,i)=>({
    ...r,
    left: 8 + ((i*17)%78),
    top: 12 + ((i*23)%66),
    tone: r.tripStatus === "delivered" ? "green" : delayed.some(d=>d.id===r.id) ? "red" : r.tripStatus === "onRoad" ? "blue" : "orange"
